import{_ as r,o as t,c as l,ai as n}from"./chunks/framework.ampVZV4B.js";const p=JSON.parse('{"title":"JVM 内存模型与垃圾回收（GC）","description":"","frontmatter":{},"headers":[],"relativePath":"java/jvm.md","filePath":"java/jvm.md"}'),s={name:"java/jvm.md"};function i(e,o,g,a,c,d){return t(),l("div",null,[...o[0]||(o[0]=[n('<h1 id="jvm-内存模型与垃圾回收-gc" tabindex="-1">JVM 内存模型与垃圾回收（GC） <a class="header-anchor" href="#jvm-内存模型与垃圾回收-gc" aria-label="Permalink to “JVM 内存模型与垃圾回收（GC）”">​</a></h1><h2 id="本模块面试重点" tabindex="-1">本模块面试重点 <a class="header-anchor" href="#本模块面试重点" aria-label="Permalink to “本模块面试重点”">​</a></h2><ul><li><strong>JVM 内存结构</strong>：能画出运行时数据区（堆、方法区、栈、程序计数器、本地方法栈），并区分哪些是线程私有、哪些是线程共享。</li><li><strong>GC 基本概念</strong>：分代收集的思想、常见 GC 算法的关键词（标记-清除、复制、标记-整理）、Minor GC / Full GC 的差别和触发场景（入门即可）。</li><li><strong>线上故障排查思路</strong>：遇到 OOM / 频繁 GC 时，知道大致用哪些工具（如 <code>jmap</code>、<code>jstat</code>、内存快照）排查问题点。</li></ul><hr><h3 id="❓-面试官-能画一下-jvm-的运行时数据区-内存模型-吗-哪些是线程私有的" tabindex="-1">❓ 面试官：能画一下 JVM 的运行时数据区（内存模型）吗？哪些是线程私有的？ <a class="header-anchor" href="#❓-面试官-能画一下-jvm-的运行时数据区-内存模型-吗-哪些是线程私有的" aria-label="Permalink to “❓ 面试官：能画一下 JVM 的运行时数据区（内存模型）吗？哪些是线程私有的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> JVM 内存主要分为 5 大区域。其中<strong>堆（Heap）</strong>和<strong>方法区（Method Area）</strong>是所有线程<strong>共享</strong>的；而<strong>虚拟机栈（Stack）</strong>、<strong>本地方法栈（Native Stack）</strong>和<strong>程序计数器（PC Register）</strong>是每个线程<strong>私有</strong>的，不会发生线程安全问题。</p><p><strong>📝 详细区域解析：</strong></p><ol><li><strong>堆（Heap）</strong>： <ul><li>占用内存最大的一块。<strong>几乎所有的对象实例和数组</strong>都在这里分配内存（&quot;几乎&quot;是因为有逃逸分析优化，对象也可能在栈上分配）。</li><li>是垃圾回收（GC）发生的主要战场。</li></ul></li><li><strong>方法区（Method Area / 元空间 Metaspace）</strong>： <ul><li>存储已被 JVM 加载的<strong>类信息（Class）、常量、静态变量（Static）、即时编译器（JIT）编译后的代码</strong>等。</li><li>在 JDK 8 之前叫“永久代（PermGen）”，JDK 8 之后移除了永久代，改存在本地内存中，称为“元空间”。</li></ul></li><li><strong>虚拟机栈（VM Stack）</strong>： <ul><li>描述的是 <strong>Java 方法执行的内存模型</strong>。每次调用一个方法，就会压入一个“栈帧（Stack Frame）”。</li><li>栈帧里存放着：局部变量表（比如你在方法里写的 <code>int a = 1</code>）、操作数栈、动态链接、方法出口信息。方法执行完自动弹栈销毁，<strong>没有 GC</strong>。</li></ul></li><li><strong>程序计数器（PC Register）</strong>： <ul><li>占用内存极小。它记录着当前线程执行到了哪一行字节码指令。因为多线程要来回切换，必须有个地方记住刚才执行到哪了。</li></ul></li><li><strong>本地方法栈（Native Method Stack）</strong>： <ul><li>和虚拟机栈类似，不过它服务的是用 <code>native</code> 关键字修饰的底层 C/C++ 方法。</li></ul></li></ol><hr><h3 id="❓-面试官-如果线上系统抛出了-oom-outofmemoryerror-你怎么排查是哪个区域溢出了-【中级】" tabindex="-1">❓ 面试官：如果线上系统抛出了 OOM（OutOfMemoryError），你怎么排查是哪个区域溢出了？【中级】 <a class="header-anchor" href="#❓-面试官-如果线上系统抛出了-oom-outofmemoryerror-你怎么排查是哪个区域溢出了-【中级】" aria-label="Permalink to “❓ 面试官：如果线上系统抛出了 OOM（OutOfMemoryError），你怎么排查是哪个区域溢出了？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 首先看 OOM 后面的报错提示信息！不同的区域溢出，报错的后缀完全不一样。根据后缀再去用对应的工具（如 <code>jmap</code>, <code>MAT</code>, <code>Arthas</code>）分析。</p><p><strong>📝 详细报错分析与场景：</strong></p><ol><li><strong><code>java.lang.OutOfMemoryError: Java heap space</code>（堆溢出）</strong>： <ul><li><strong>原因</strong>：最常见的 OOM。堆里塞满了活生生的对象，GC 怎么清理都清理不掉（通常是内存泄漏，或者瞬间读取了千万级的数据到内存）。</li><li><strong>排查</strong>：在启动参数里加上 <code>-XX:+HeapDumpOnOutOfMemoryError</code>，拿到 <code>.hprof</code> 堆转储快照文件，用 Eclipse MAT 等工具打开，一眼就能看到是哪个类的对象占了 90% 的内存。</li></ul></li><li><strong><code>java.lang.StackOverflowError</code>（栈溢出）</strong>： <ul><li><strong>原因</strong>：这不是 OOM，但也很常见。通常是写了<strong>无限递归（死循环调用方法）</strong>，导致栈帧一层一层往上叠，最终把栈深度撑爆了。</li></ul></li><li><strong><code>java.lang.OutOfMemoryError: Metaspace</code>（元空间溢出）</strong>： <ul><li><strong>原因</strong>：方法区被塞满了。通常是因为在运行期间，通过 CGLib 等动态字节码技术生成了<strong>海量的动态代理类（Class）</strong>，把方法区撑爆了。</li></ul></li></ol><hr><h3 id="❓-面试官-什么是垃圾回收-gc-jvm-怎么判断一个对象是不是垃圾" tabindex="-1">❓ 面试官：什么是垃圾回收（GC）？JVM 怎么判断一个对象是不是垃圾？ <a class="header-anchor" href="#❓-面试官-什么是垃圾回收-gc-jvm-怎么判断一个对象是不是垃圾" aria-label="Permalink to “❓ 面试官：什么是垃圾回收（GC）？JVM 怎么判断一个对象是不是垃圾？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> GC 就是自动清理掉内存中那些<strong>“没用的对象”</strong>。JVM 判断对象是不是垃圾，不使用引用计数法，而是使用 <strong>可达性分析算法（GC Roots Tracing）</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>为什么不用引用计数法？</strong>： <ul><li>理念：给对象加个计数器，被引用 1 次就 +1，断开就 -1，为 0 就当垃圾回收。</li><li>致命缺陷：<strong>循环引用（内存泄漏）</strong>。A 引用 B，B 引用 A，但它们俩谁都没在用了，计数器都是 1，导致永远无法被回收。</li></ul></li><li><strong>可达性分析算法（主流做法）</strong>： <ul><li>理念：找几个绝对不能被当成垃圾的“祖宗节点”（<strong>GC Roots</strong>）。从这几个祖宗节点开始，顺着引用链往下找（就像葡萄藤一样）。</li><li>凡是能被这根藤牵出来的对象，都是“存活的”（可达）；凡是断在一旁，跟这根藤没有任何联系的对象，统统判定为垃圾（不可达）。</li></ul></li></ol><p><strong>🌟 面试加分项（实战底层）：</strong> 面试官常追问：“那到底哪些对象能作为 GC Roots（祖宗节点）？” <strong>绝杀回答</strong>： 主要有四种：</p><ol><li><strong>虚拟机栈</strong>中（局部变量表）正在引用的对象。</li><li><strong>方法区中静态属性</strong>（<code>static</code>）引用的对象。</li><li><strong>方法区中常量</strong>（<code>final</code>）引用的对象。</li><li><strong>本地方法栈</strong>中（<code>native</code> 方法）引用的对象。</li></ol><hr><h3 id="❓-面试官-讲讲堆内存的分代模型-以及-minor-gc-和-full-gc-的区别-【中高级】" tabindex="-1">❓ 面试官：讲讲堆内存的分代模型，以及 Minor GC 和 Full GC 的区别？【中高级】 <a class="header-anchor" href="#❓-面试官-讲讲堆内存的分代模型-以及-minor-gc-和-full-gc-的区别-【中高级】" aria-label="Permalink to “❓ 面试官：讲讲堆内存的分代模型，以及 Minor GC 和 Full GC 的区别？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 为了提高垃圾回收效率，JVM（如 JDK 8 默认的 CMS/Parallel 组合）把堆内存分为了<strong>新生代（Young Gen）</strong>和<strong>老年代（Old Gen）</strong>。新生代发生的清理叫 <strong>Minor GC</strong>（速度极快），老年代发生的清理叫 <strong>Full GC</strong>（速度极慢，会引发长期的系统停顿 STW）。</p><p><strong>📝 详细分代与流转机制（必背）：</strong></p><ol><li><strong>新生代（占比 1/3）</strong>： <ul><li>又细分为一个 Eden 区（伊甸园）和两个 Survivor 区（S0 和 S1，通常比例是 8:1:1）。</li><li><strong>新对象出生</strong>：绝大多数刚 <code>new</code> 出来的新对象，都放在 Eden 区。</li><li><strong>Minor GC（清理新生代）</strong>：当 Eden 区满了，触发 Minor GC。存活下来的对象会被复制到一个空闲的 Survivor 区，同时年龄 +1。</li><li><strong>特点</strong>：绝大多数对象都是“朝生夕死”的（比如一个接口里的局部变量对象，接口结束就没用了），所以 Minor GC 发生极其频繁，且非常高效。</li></ul></li><li><strong>老年代（占比 2/3）</strong>： <ul><li>里面存放的都是“生命力极其顽强”的长期存活对象（比如 Spring 里的单例 Bean、本地缓存对象）。</li><li><strong>晋升条件</strong>： <ul><li>年龄达标：默认对象在 Survivor 区熬过 15 次 Minor GC 后，晋升到老年代。</li><li>大对象直接进入：极其庞大的数组或长字符串，直接扔进老年代（防止在两个 Survivor 区之间来回复制极其耗费性能）。</li></ul></li><li><strong>Full GC（全堆清理）</strong>：当老年代也满了，就会触发 Full GC。它不仅要清理老年代，通常还会顺带清理新生代和方法区。</li><li><strong>致命痛点（STW）</strong>：Full GC 发生时，整个 JVM 会产生 <strong>Stop-The-World（STW）</strong> 现象，所有业务线程全部被强行暂停！如果发生频繁，会导致接口严重卡顿、超时。</li></ul></li></ol><p><strong>🌟 面试拔高（排查思路）：</strong> &quot;在日常线上调优中，我们的终极目标就是<strong>尽量减少 Full GC 的频率</strong>。比如遇到由于设置了过大的本地 <code>HashMap</code> 缓存且从不清理，导致老年代频繁撑满触发几十秒的 Full GC 卡顿，我们最终通过更换为带有自动过期淘汰机制的 <code>Caffeine</code> 缓存彻底解决了问题。&quot;</p>',30)])])}const m=r(s,[["render",i]]);export{p as __pageData,m as default};
